const listPendingHosts = `-- name: ListPendingHosts :many
SELECT id, onboarding_mode, approval_status, approved_at, display_name, machine_id, hostname, ip_address, os_family, os_name, os_major, os_version, architecture, status, last_seen_at, last_advisory_check_at, first_seen_at, last_snapshot_id, created_at, updated_at, advisory_scope_key
FROM hosts
WHERE approval_status = 'waiting_approval'
ORDER BY created_at DESC, id DESC
`

func (q *Queries) ListPendingHosts(ctx context.Context) ([]Host, error) {
	rows, err := q.db.Query(ctx, listPendingHosts)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []Host
	for rows.Next() {
		var i Host
		if err := rows.Scan(
			&i.ID,
			&i.OnboardingMode,
			&i.ApprovalStatus,
			&i.ApprovedAt,
			&i.DisplayName,
			&i.MachineID,
			&i.Hostname,
			&i.IpAddress,
			&i.OsFamily,
			&i.OsName,
			&i.OsMajor,
			&i.OsVersion,
			&i.Architecture,
			&i.Status,
			&i.LastSeenAt,
			&i.LastAdvisoryCheckAt,
			&i.FirstSeenAt,
			&i.LastSnapshotID,
			&i.CreatedAt,
			&i.UpdatedAt,
			&i.AdvisoryScopeKey,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

