const updateSSHPullRun = `-- name: UpdateSSHPullRun :exec
WITH updated_pull AS (
    UPDATE host_ssh_pull
    SET
        pull_last_run_at = $1,
        pull_last_run_status = $12,
        pull_last_run_error = $13
    WHERE host_id = $11
)
UPDATE hosts
SET
    last_advisory_check_at = $1,
    last_snapshot_id = COALESCE($2, last_snapshot_id),
    machine_id = COALESCE($3, machine_id),
    hostname = COALESCE($4, hostname),
    ip_address = COALESCE($5, ip_address),
    os_family = CASE WHEN $6::text <> '' AND $6::text <> 'unknown' THEN $6 ELSE os_family END,
    os_name = CASE WHEN $7::text <> '' AND $7::text <> 'Unknown' THEN $7 ELSE os_name END,
    os_major = CASE WHEN $8::integer <> 0 THEN $8 ELSE os_major END,
    os_version = CASE WHEN $9::text <> '' AND $9::text <> 'unknown' THEN $9 ELSE os_version END,
    architecture = CASE WHEN $10::text <> '' AND $10::text <> 'unknown' THEN $10 ELSE architecture END,
    last_seen_at = COALESCE($1, last_seen_at)
WHERE id = $11
`

type UpdateSSHPullRunParams struct {
	PullLastRunAt     pgtype.Timestamptz
	LastSnapshotID    utils.Option[string]
	MachineID         utils.Option[string]
	Hostname          utils.Option[string]
	IpAddress         utils.Option[string]
	OsFamily          string
	OsName            string
	OsMajor           int32
	OsVersion         string
	Architecture      string
	ID                string
	PullLastRunStatus utils.Option[string]
	PullLastRunError  utils.Option[string]
}

func (q *Queries) UpdateSSHPullRun(ctx context.Context, arg UpdateSSHPullRunParams) error {
	_, err := q.db.Exec(ctx, updateSSHPullRun,
		arg.PullLastRunAt,
		arg.LastSnapshotID,
		arg.MachineID,
		arg.Hostname,
		arg.IpAddress,
		arg.OsFamily,
		arg.OsName,
		arg.OsMajor,
		arg.OsVersion,
		arg.Architecture,
		arg.ID,
		arg.PullLastRunStatus,
		arg.PullLastRunError,
	)
	return err
}
